Code Good:
type Batcher[T any] struct {
    size    int
    timeout time.Duration
    flush   func([]T) error
}

func (b *Batcher[T]) Run(ctx context.Context, in <-chan T) error {
    batch := make([]T, 0, b.size)
    timer := time.NewTimer(b.timeout)
    defer timer.Stop()
    for {
        select {
        case item, ok := <-in:
            if !ok {
                if len(batch) > 0 {
                    return b.flush(batch)
                }
                return nil
            }
            batch = append(batch, item)
            if len(batch) >= b.size {
                if err := b.flush(batch); err != nil {
                    return err
                }
                batch = batch[:0]
                timer.Reset(b.timeout)
            }
        case <-timer.C:
            if len(batch) > 0 {
                if err := b.flush(batch); err != nil {
                    return err
                }
                batch = batch[:0]
            }
            timer.Reset(b.timeout)
        case <-ctx.Done():
            if len(batch) > 0 {
                return b.flush(batch)
            }
            return ctx.Err()
        }
    }
}

