import "golang.org/x/time/rate"

func rateLimited(ctx context.Context, in <-chan Request, rps int) <-chan Response {
    out := make(chan Response)
    limiter := rate.NewLimiter(rate.Limit(rps), rps)
    go func() {
        defer close(out)
        for req := range in {
            if err := limiter.Wait(ctx); err != nil {
                return
            }
            resp, err := callExternalAPI(ctx, req)
            if err != nil {
                log.Printf("api error: %v", err)
                continue
            }
            select {
            case out <- resp:
            case <-ctx.Done():
                return
            }
        }
    }()
    return out
}

