func runPipeline(ctx context.Context) error {
    ctx, cancel := signal.NotifyContext(ctx, syscall.SIGTERM, syscall.SIGINT)
    defer cancel()

    items := make(chan Item, 100)
    var wg sync.WaitGroup

    // Producer stops on context cancellation
    wg.Add(1)
    go func() {
        defer wg.Done()
        defer close(items)
        for {
            item, err := fetchNext(ctx)
            if err != nil {
                return
            }
            select {
            case items <- item:
            case <-ctx.Done():
                return
            }
        }
    }()

    // Workers drain remaining items after producer stops
    for i := 0; i < 4; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for item := range items {
                process(item)
            }
        }()
    }

    wg.Wait()
    return nil
}

