func processWithDLQ(ctx context.Context, consumer sarama.ConsumerGroupClaim, sess sarama.ConsumerGroupSession, dlqProducer sarama.SyncProducer) {
    for msg := range consumer.Messages() {
        var err error
        for attempt := 0; attempt < 3; attempt++ {
            if err = processMessage(msg.Value); err == nil {
                break
            }
            time.Sleep(time.Duration(attempt+1) * 100 * time.Millisecond)
        }
        if err != nil {
            headers := []sarama.RecordHeader{
                {Key: []byte("original-topic"), Value: []byte(msg.Topic)},
                {Key: []byte("error"), Value: []byte(err.Error())},
                {Key: []byte("failed-at"), Value: []byte(time.Now().Format(time.RFC3339))},
            }
            dlqProducer.SendMessage(&sarama.ProducerMessage{
                Topic:   msg.Topic + ".dlq",
                Key:     sarama.ByteEncoder(msg.Key),
                Value:   sarama.ByteEncoder(msg.Value),
                Headers: headers,
            })
        }
        sess.MarkMessage(msg, "")
    }
}

