import (
    "github.com/prometheus/client_golang/prometheus"
    "github.com/prometheus/client_golang/prometheus/promauto"
)

var (
    itemsProcessed = promauto.NewCounterVec(prometheus.CounterOpts{
        Name: "pipeline_items_processed_total",
        Help: "Total items processed per stage",
    }, []string{"stage", "status"})

    processingDuration = promauto.NewHistogramVec(prometheus.HistogramOpts{
        Name:    "pipeline_processing_duration_seconds",
        Help:    "Processing duration per stage",
        Buckets: []float64{.001, .005, .01, .05, .1, .5, 1},
    }, []string{"stage"})

    queueDepth = promauto.NewGaugeVec(prometheus.GaugeOpts{
        Name: "pipeline_queue_depth",
        Help: "Current items in stage queue",
    }, []string{"stage"})
)

func instrumentedProcess(stage string, item Item) error {
    timer := prometheus.NewTimer(processingDuration.WithLabelValues(stage))
    defer timer.ObserveDuration()
    if err := process(item); err != nil {
        itemsProcessed.WithLabelValues(stage, "error").Inc()
        return err
    }
    itemsProcessed.WithLabelValues(stage, "success").Inc()
    return nil
}

