type Pool struct {
    workers int
    jobs    chan func()
    wg      sync.WaitGroup
}

func NewPool(workers int) *Pool {
    p := &Pool{
        workers: workers,
        jobs:    make(chan func(), workers*2),
    }
    for i := 0; i < workers; i++ {
        p.wg.Add(1)
        go func() {
            defer p.wg.Done()
            for job := range p.jobs {
                job()
            }
        }()
    }
    return p
}

func (p *Pool) Submit(job func()) { p.jobs <- job }

func (p *Pool) Shutdown() {
    close(p.jobs)
    p.wg.Wait()
}

