import "sync"

var bufferPool = sync.Pool{
    New: func() any {
        b := make([]byte, 0, 4096)
        return &b
    },
}

func processItem(data []byte) ([]byte, error) {
    bufPtr := bufferPool.Get().(*[]byte)
    buf := (*bufPtr)[:0]
    defer func() {
        *bufPtr = buf
        bufferPool.Put(bufPtr)
    }()

    buf = append(buf, data...)
    // ... transform buf ...
    result := make([]byte, len(buf))
    copy(result, buf)
    return result, nil
}

