Code Good:
type Checkpoint struct {
    mu       sync.Mutex
    store    *sql.DB
    pipeline string
}

func (c *Checkpoint) Save(ctx context.Context, offset int64) error {
    c.mu.Lock()
    defer c.mu.Unlock()
    _, err := c.store.ExecContext(ctx,
        "INSERT INTO checkpoints (pipeline, offset, updated_at) VALUES ($1, $2, NOW()) ON CONFLICT (pipeline) DO UPDATE SET offset = $2, updated_at = NOW()",
        c.pipeline, offset)
    return err
}

func (c *Checkpoint) Load(ctx context.Context) (int64, error) {
    var offset int64
    err := c.store.QueryRowContext(ctx,
        "SELECT offset FROM checkpoints WHERE pipeline = $1",
        c.pipeline).Scan(&offset)
    if err == sql.ErrNoRows {
        return 0, nil
    }
    return offset, err
}

