}

func decodeEvent(data []byte) (*pb.Event, error) {
    e := &pb.Event{}
    if err := proto.Unmarshal(data, e); err != nil {
        return nil, fmt.Errorf("unmarshal event: %w", err)
    }
    return e, nil
}

