    "github.com/testcontainers/testcontainers-go"
    "github.com/testcontainers/testcontainers-go/modules/kafka"
)

func TestPipelineEndToEnd(t *testing.T) {
    ctx := context.Background()
    kafkaC, err := kafka.Run(ctx, "confluentinc/confluent-local:7.5.0")
    if err != nil {
        t.Fatalf("starting kafka: %v", err)
    }
    defer kafkaC.Terminate(ctx)

    brokers, err := kafkaC.Brokers(ctx)
    if err != nil {
        t.Fatalf("getting brokers: %v", err)
    }

    // Produce test messages
    producer := newProducer(t, brokers)
    for i := 0; i < 100; i++ {
        produce(t, producer, "input-topic", testEvent(i))
    }

    // Run pipeline
    pCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
    defer cancel()
    go RunPipeline(pCtx, brokers, "input-topic", "output-topic")

    // Verify output
    results := consumeAll(t, brokers, "output-topic", 100, 30*time.Second)
    assert.Len(t, results, 100)
    for _, r := range results {
        assert.NotEmpty(t, r.ProcessedAt)
    }
}

